sql:
SELECT DISTINCT users.user_name, users.email
FROM users
JOIN demographic_changes ON users.user_id = demographic_changes.changed_by;

SELECT county_name
FROM counties
WHERE state_id = 1 AND population > 20000;

external_knowledge:
- "gleaners of information" refers to users who have accessed reports;
- "harvested the ripest fruits of knowledge" means they have accessed the latest versions of reports;
- "fully blossomed knowledge trees" refers to reports that are in the 'published' status;
- "names and the most recent editions of these fruits" refers to the report names and their latest version numbers.

sql:
SELECT change_date, old_value, new_value, reason
FROM demographic_changes
WHERE demographic_id = 1;

SELECT file_path
FROM reports
WHERE status = 'published';

SELECT reason 
FROM demographic_changes 
WHERE change_id = 0;

SELECT 
    (SELECT AVG(population) FROM counties WHERE state_id = 1) AS avg_population,
    (SELECT AVG(duration) FROM access_logs JOIN users ON access_logs.user_id = users.user_id WHERE users.role = 'admin') AS avg_access_duration;
